import { useMemo } from 'react';
import type { SearchInputConfig } from '@linm-soft-org/linm-web-common-components';
import { mapCatalogSchemaToSearchConfig } from '../components/catalog/catalogUiSchema/mapCatalogSchemaToSearchConfig';
import { useCatalogUiSchema } from '../components/listUiSchema';
import { LIST_UI_SCHEMA_KIND } from '../types/catalogUiSchema';
import { wmsService } from '../services/kho/wmsService';
import type { MaterialDto } from '../services/kho/models';

/** Material line search — columns from BE `materials` ui-schema (GAP catalog-lookup-from-schema). */
export function useMaterialSearchFromSchema(): SearchInputConfig<MaterialDto> | null {
  const { schema, loading } = useCatalogUiSchema(LIST_UI_SCHEMA_KIND.materials);
  return useMemo(() => {
    if (loading || !schema) return null;
    return mapCatalogSchemaToSearchConfig<MaterialDto>(schema, {
      search: async params => {
        const pageSize = params.pageSize ?? 20;
        const r = await wmsService.searchMaterials({
          search: params.search,
          page: params.page ?? 1,
          pageSize,
        });
        return {
          items: r.items,
          totalCount: r.totalPages * pageSize,
          page: r.page,
          pageSize,
        };
      },
      getItemKey: m => m.code,
      getPrimaryDisplay: m => m.code,
      getSecondaryDisplay: m => m.name,
    });
  }, [schema, loading]);
}
